  "extraction": {
    "status": "candidates_found",
    "extracted_at": "2026-06-12T19:20:01",
    "extractor": "agent",
    "summary": "The paper analyses kinematics of 30 extreme disk-runaway stars using Gaia EDR3 and spectrophotometric distances. Ten objects are treated as gravitationally unbound or possibly hyper-runaway from the Milky Way: S5-HVS 1, HVS 5, HVS 6, LAMOST HVS 1, LAMOST HVS 4, B481, HVS 7, LAMOST HVS 2, J0136+2425, and HVS 8. The remaining 20 program stars are bound. RA/Dec and proper motions are not tabulated in the paper and therefore not extracted; observed phase space is limited to radial velocity and distance. Derived Galactocentric kinematics and bound probabilities (P_b) are taken from the full kinematics table.",
    "tooling": {
      "agent_runtime": "stella-agent-v0.1",
      "model_id": "claude-sonnet-4-20250514-extraction-pipeline",
      "prompt_version": "v0.1",
      "request_parameters": {
        "temperature": 0.0
      }
    }
  },
  "method_chain": [
    {
      "id": "step-01",
      "depends_on": [],
      "step_type": "input_catalog",
      "summary": "Initial sample from MMT-HVS survey (~40 high-velocity late B-type stars, Brown et al. 2014), 30 runaway stars from Silva & Napiwotzki (2011) collection, prototype hyper-runaway HD 271791, potential hyper-runaway stars J0136+2425 and HIP 60350, extreme disk-runaway PG 1610+062, four LAMOST HVS candidates, and the probable Hills star S5-HVS 1 (Koposov et al. 2020). All objects cross-matched with Gaia EDR3 for proper motions and astrometry.",
      "inputs": [
        "Gaia EDR3 proper motions and astrometry",
        "MMT-HVS catalog (Brown et al. 2014)",
        "LAMOST HVS candidates",
        "Literature collection of runaway stars"
      ],
      "outputs": [
        "Initial sample of high-velocity early-type stars with Gaia EDR3 identifiers"
      ],
      "parameters": [],
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2101.10878/arxiv_source/paper.tex",
          "start_line": 97,
          "end_line": 97,
          "context": "Our initial sample comprised all 40 stars of the MMT-HVS survey that were revised by Kreuzer+2020, together with 30 runaway stars from the collection of Silva & Napiwotzki (2011) ..."
        }
      ]
    },
    {
      "id": "step-02",
      "depends_on": [
        "step-01"
      ],
      "step_type": "sample_selection",
      "summary": "Filter to extreme disk-runaway candidates using mass-dependent ejection velocity threshold (v_ej,1sigma upper limit > 400 km/s for M<5 Msun, > 320 km/s for M>5 Msun) and disk origin (1-sigma lower limit of galactocentric plane-crossing radius r_p < 25 kpc). Visual inspection confirms well-constrained origin. Final sample of 30 program stars (Table 1).",
      "inputs": [
        "Initial sample",
        "Preliminary kinematic analysis"
      ],
      "outputs": [
        "30 program stars"
      ],
      "parameters": [],
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2101.10878/arxiv_source/paper.tex",
          "start_line": 97,
          "end_line": 97,
          "context": "Based on proper motions from Gaia EDR3, we then carried out spectroscopic and kinematic analyses ... to filter out those with both a high ejection velocity and a relatively well-constrained origin ..."
        }
      ]
    },
    {
      "id": "step-03",
      "depends_on": [
        "step-01"
      ],
      "step_type": "cross_match",
      "summary": "Cross-match program stars with Gaia EDR3 to obtain precise proper motions and Gaia source IDs.",
      "inputs": [
        "Program star list",
        "Gaia EDR3 catalog"
      ],
      "outputs": [
        "Gaia EDR3 source IDs and proper motions for 30 stars"
      ],
      "parameters": [],
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2101.10878/arxiv_source/paper.tex",
          "start_line": 97,
          "end_line": 97,
          "context": "Based on proper motions from Gaia EDR3 ..."
        }
      ]
    },
    {
      "id": "step-04",
      "depends_on": [
        "step-02"
      ],
      "step_type": "distance_estimation",
      "summary": "Spectrophotometric distances derived from quantitative spectral analysis (Teff, log g, v sin i, v_rad) and SED fitting to obtain angular diameter and interstellar extinction. Stellar mass and radius inferred from evolutionary tracks. Distance d = 2R/Theta (Table A.1).",
      "inputs": [
        "Optical spectra (various instruments)",
        "Photometry (UV, optical, IR)"
      ],
      "outputs": [
        "Stellar parameters (Table A.1)",
        "Spectrophotometric distances"
      ],
      "parameters": [],
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2101.10878/arxiv_source/paper.tex",
          "start_line": 149,
          "end_line": 153,
          "context": "Section 3: Quantitative spectrophotometric analysis ... distances estimated from the measured parallaxes ... we used spectrophotometric distance estimates as input ..."
        }
      ]
    },
    {
      "id": "step-05",
      "depends_on": [
        "step-04"
      ],
      "step_type": "radial_velocity_measurement",
      "summary": "Radial velocities measured from optical spectra via fitting model spectra. Values listed in Table A.1 (v_rad column).",
      "inputs": [
        "Optical spectra"
      ],
      "outputs": [
        "Radial velocities (v_rad)"
      ],
      "parameters": [],
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2101.10878/arxiv_source/paper.tex",
          "start_line": 153,
          "end_line": 153,
          "context": "Atmospheric parameters such as ... radial velocity v_rad were determined by fitting the most recent model spectra ..."
        }
      ]
    },
    {
      "id": "step-07",
      "depends_on": [],
      "step_type": "solar_position_and_motion",
      "summary": "Solar Galactocentric distance R0 = 8.3 kpc (solar circle depicted in figures). Solar motion relative to the local standard of rest adopted from Schönrich et al. (2010) with uncertainties propagated in Monte Carlo error analysis. The specific U, V, W values are not listed in the paper.",
      "inputs": [],
      "outputs": [
        "Solar position R0, z0",
        "Solar peculiar motion (U,V,W)"
      ],
      "parameters": [
        {
          "name": "R0",
          "raw_value": "8.3",
          "value": "8.3",
          "unit": "kpc",
          "description": "Adopted distance to the Galactic center; explicitly shown as solar circle in figures.",
          "source_refs": [
            {
              "kind": "text",
              "path": "literature/2101.10878/arxiv_source/paper.tex",
              "start_line": 146,
              "end_line": 146,
              "context": "circles centered at the GC ... radii of 1 kpc, 8.3 kpc (solar circle; dashed red line), 25 kpc"
            }
          ]
        },
