          "unit": "kpc",
          "description": "Sun assumed at Galactic mid-plane.",
          "source_refs": []
        },
        {
          "name": "v_circ_sun",
          "raw_value": "not_reported",
          "value": "",
          "unit": "km/s",
          "description": "Local circular velocity not explicitly stated; from Schönrich et al. (2010).",
          "source_refs": []
        },
        {
          "name": "solar_motion_u",
          "raw_value": "not_reported",
          "value": "",
          "unit": "km/s",
