      "depends_on": [
        "step-09"
      ],
      "step_type": "escape_or_bound_assessment",
      "summary": "Bound/unbound assessment via Monte Carlo: compute v_Grf and v_Grf - v_esc. Fraction of runs with v_Grf < v_esc gives bound probability P_b (Table A.2, column P_b). Stars with P_b=0 are definitely unbound. Escape margin v_Grf - v_esc > 0 implies unbound.",
      "inputs": [
        "Monte Carlo kinematic samples"
      ],
      "outputs": [
        "v_Grf - v_esc",
        "Bound probability P_b"
      ],
      "parameters": [],
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2101.10878/arxiv_source/paper.tex",
          "start_line": 161,
          "end_line": 161,
          "context": "Ejection velocities ... are also given in Table A.2 ..."
        },
        {
          "kind": "text",
          "path": "literature/2101.10878/arxiv_source/paper.tex",
          "start_line": 742,
          "end_line": 743,
          "context": "The probability P_b is the fraction of Monte Carlo runs for which the star is bound to the Milky Way."
        }
      ]
    },
    {
      "id": "step-11",
      "depends_on": [
        "step-09",
        "step-10"
      ],
      "step_type": "origin_assessment",
